from kafka import KafkaConsumer
import json

class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers, topics):
        self.consumer = KafkaConsumer(
            *topics,
            bootstrap_servers=bootstrap_servers,
            auto_offset_reset='earliest',
            enable_auto_commit=True,
            value_deserializer=lambda x: json.loads(x.decode('utf-8'))
        )

    def start_consuming(self):
        for message in self.consumer:
            topic = message.topic
            partition = message.partition
            offset = message.offset
            key = message.key
            value = message.value

            print(f"Received message from topic: {topic}, partition: {partition}, offset: {offset}, key: {key}")
            self.process_message(value)

    def process_message(self, value):
        transaction_type = value.get('type')
        if transaction_type == 'credit':
            self.handle_credit_transaction(value)
        elif transaction_type == 'debit':
            self.handle_debit_transaction(value)
        # Add more transaction types and handlers as needed

    def handle_credit_transaction(self, value):
        amount = value.get('amount')
        account_id = value.get('account_id')
        print(f"Processing credit transaction: Amount {amount}, Account ID {account_id}")

    def handle_debit_transaction(self, value):
        amount = value.get('amount')
        account_id = value.get('account_id')
        print(f"Processing debit transaction: Amount {amount}, Account ID {account_id}")

if __name__ == "__main__":
    consumer = FinancialTransactionConsumer(bootstrap_servers='localhost:9092', topics=['financial_transactions'])
    consumer.start_consuming()